#!/usr/bin/env node
/**
 * Reads the bundled Katalon keyword libraries and emits a generated module
 * the AI accelerators import at runtime. Re-run after editing /katalon sources.
 */
import { readFileSync, writeFileSync } from 'fs'
import { dirname, join } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const root = join(__dirname, '..')
const kwDir = join(root, 'katalon/Keywords/com/nttdata/guidewire')

const FILES = {
  GuidewireUI: 'GuidewireUI.groovy',
  LoginActions: 'LoginActions.groovy',
  TestData: 'TestData.groovy',
  PolicyCenterActions: 'PolicyCenterActions.groovy',
  ClaimCenterActions: 'ClaimCenterActions.groovy',
  BillingCenterActions: 'BillingCenterActions.groovy',
  JutroActions: 'JutroActions.groovy'
}

const libraries = {}
for (const [key, file] of Object.entries(FILES)) {
  libraries[key] = readFileSync(join(kwDir, file), 'utf8')
}

const out = `// AUTO-GENERATED by scripts/bundle-katalon-reference.js — do not edit by hand.
// Re-run: npm run bundle:katalon

export const KATALON_SHARED_LIBS = ${JSON.stringify(
  ['GuidewireUI', 'LoginActions', 'TestData'],
  null,
  2
)}

export const KATALON_PRODUCT_LIBS = ${JSON.stringify(
  {
    PolicyCenter: 'PolicyCenterActions',
    ClaimCenter: 'ClaimCenterActions',
    BillingCenter: 'BillingCenterActions',
    Jutro: 'JutroActions',
    'Cross-suite': ['PolicyCenterActions', 'ClaimCenterActions', 'BillingCenterActions', 'JutroActions']
  },
  null,
  2
)}

export const KATALON_LIBRARIES = ${JSON.stringify(libraries, null, 2)}
`

writeFileSync(join(root, 'src/lib/katalonReference.generated.js'), out)
console.log('Wrote src/lib/katalonReference.generated.js')
